const data = $json.records || [];

  // --- Helpers ---
  function bufferToBool(value) {
    if (value && typeof value === 'object' && value.type === 'Buffer' && Array.isArray(value.data) && value.data.length > 0) {
      const char = String.fromCharCode(value.data[0]);
      const c = char.toUpperCase();
      if (['T', 'Y', '1'].includes(c)) return true;
      if (['F', 'N', '0'].includes(c)) return false;
    }
    if (typeof value === 'boolean') return value;
    if (typeof value === 'number') return value !== 0;
    if (typeof value === 'string') {
      const s = value.trim().toLowerCase();
      if (['true', 't', 'yes', 'y', '1'].includes(s)) return true;
      if (['false', 'f', 'no', 'n', '0'].includes(s)) return false;
    }
    return Boolean(value);
  }

  function normalizeProduct(fields) {
    return {
      sku: fields.sku,
      name: fields.name,
      unit_name: fields.unit_name,
      price: fields.price,
      style: fields.style,
      height_in: fields.height_in,
      width_in: fields.width_in,
      rail_type: fields.rail_type,
      bottom_type: fields.bottom_type,
      post_thickness: fields.post_thickness,
      box_qty: fields.box_qty,
      note: fields.note,
    };
  }

  // --- Normalize all products ---
  const products = data.map(r => {
    const fields = r.fields || r;
    return normalizeProduct(fields);
  });

  const totalCount = products.length;

  // --- Determine mode ---
  let mode;
  if (totalCount === 0) mode = 'none';
  else if (totalCount === 1) mode = 'exact';
  else if (totalCount <= 5) mode = 'full';
  else if (totalCount <= 20) mode = 'guided';
  else mode = 'narrow';

  // --- Compute facets (only if more than 5 results) ---
  const FACET_FIELDS = ['unit_name', 'style', 'height_in', 'width_in', 'rail_type', 'bottom_type', 'post_thickness'];

  let facets = null;
  let suggested_filter = null;

  if (totalCount > 5) {
    facets = {};

    for (const field of FACET_FIELDS) {
      const counts = {};
      for (const p of products) {
        const val = p[field];
        if (val !== null && val !== undefined && val !== '') {
          counts[val] = (counts[val] || 0) + 1;
        }
      }

      const uniqueValues = Object.keys(counts);
      if (uniqueValues.length > 1) {  // Only include if multiple options
        facets[field] = {
          values: uniqueValues,
          counts: uniqueValues.map(v => counts[v])
        };
      }
    }

    // Find most discriminating field (closest to 50/50 split)
    let bestField = null;
    let bestScore = 0;

    for (const [field, data] of Object.entries(facets)) {
      const maxCount = Math.max(...data.counts);
      const score = 1 - (maxCount / totalCount);  // Higher = more even distribution
      if (score > bestScore && data.values.length >= 2) {
        bestScore = score;
        bestField = field;
      }
    }

    suggested_filter = bestField;
  }

  // --- Build response ---
  const response = {
    mode,
    total_count: totalCount,
    products: products.slice(0, 5),  // Top 5 only for LLM
  };

  if (facets && Object.keys(facets).length > 0) {
    response.facets = facets;
    response.suggested_filter = suggested_filter;
  }

  if (mode === 'none') {
    response.message = "No products found matching your criteria.";
  }

  return [{ json: response }];

const items = $('When Executed from MCP Trigger Call').all();

function notEmpty(value) {
  if (value === undefined || value === null) return false;
  if (typeof value === 'string' && value.trim() === '') return false;
  return true;
}

const TABLE_NAME = 'Products_summary_active_description_family_code_name_price_sku_unit_code';

const PRODUCT_COLUMNS = [
  'sku','family_code','unit_name','name','price','box_qty','post_thickness','true_gate_width_in',
  'style','bottom_type','width_in','vendor_sku','height_in','note','rail_type'
].join(', ');

const FACET_FIELDS = ['unit_name','style','height_in','width_in','rail_type','bottom_type','post_thickness'];

return items.map(item => {
  const q = item.json.query || item.json || {};
  const where = [];
  const args = [];

  where.push('family_code = ?');
  args.push(2);

  if (notEmpty(q.unit_name)) { where.push('unit_name = ?'); args.push(q.unit_name); }
  if (notEmpty(q.style)) { where.push('style = ?'); args.push(q.style); }
  if (notEmpty(q.height_in) && Number(q.height_in) !== 0) { where.push('height_in = ?'); args.push(Number(q.height_in)); }
  if (notEmpty(q.width_in) && Number(q.width_in) !== 0) { where.push('width_in = ?'); args.push(Number(q.width_in)); }

  if (notEmpty(q.price_gte) && Number(q.price_gte) !== 0) { where.push('price >= ?'); args.push(Number(q.price_gte)); }
  if (notEmpty(q.price_lte) && Number(q.price_lte) !== 0) { where.push('price <= ?'); args.push(Number(q.price_lte)); }

  const active = typeof q.active === 'boolean' ? q.active : true;
  where.push('active = ?');
  args.push(active);

  const whereClause = ' WHERE ' + where.join(' AND ');

  const productsSql =
    `SELECT ${PRODUCT_COLUMNS}, ` +
    `(SELECT COUNT(*) FROM ${TABLE_NAME}${whereClause}) AS total_count ` +
    `FROM ${TABLE_NAME}${whereClause} ` +
    `ORDER BY price DESC, unit_name, style, height_in, width_in ` +
    `LIMIT 5`;

  const facetsSql = FACET_FIELDS.map(field =>
    `SELECT '${field}' AS field, ${field} AS value, COUNT(*) AS cnt ` +
    `FROM ${TABLE_NAME}${whereClause} ` +
    `AND ${field} IS NOT NULL AND ${field} != '' ` +
    `GROUP BY ${field}`
  ).join(' UNION ALL ');

  const facetsArgs = [];
  for (let i = 0; i < FACET_FIELDS.length; i++) facetsArgs.push(...args);

  return {
    json: {
      ...item.json,
      productsSql,
      productsArgs: [...args, ...args], // duplicated because productsSql uses where twice
      facetsSql,
      facetsArgs,
    },
  };
});
